var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"힘조절도 없이 무식하게 다 부숴버리다니.","JPN":"力加減もなく全部壊してしまうなんて。","ENG":"You destroyed everything in sight.","TWN":"完全沒拿捏力道，就這樣隨便亂砸。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"무사라는 이름을 가지고 있으면, 좀 더 섬세해야 하지 않아?","JPN":"武士って名前があるのなら、もっとデリケートでないと。","ENG":"Don’t you think you should be more delicate if you come from a samurai family?","TWN":"身為武士不是應該更細膩一點嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나는 내 역할에 충실할 뿐이다.","JPN":"私は自分の役割に忠実であるだけだ。","ENG":"I adhere to my duties.","TWN":"我只是忠於我的職責。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아하~","JPN":"あは～","ENG":"Oh?","TWN":"哈哈～"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"우리 발을 묶어 두고 소란을 일으켜서 위치를 알리는 역할 말이지?","JPN":"私たちの足止めをしては騒ぎを起こし、位置を知らせる役割のことかしら？","ENG":"You mean your duty of notifying our location and buying time for the reinforcement?","TWN":"你的職責就是困住我們，引起騷動，透露出位置嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아니면……","JPN":"それとも……","ENG":"Or...","TWN":"還是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"……내 뒤를 기습할 때까지 시선을 돌린다거나?","JPN":"……私の背後から不意打ちするまで視線を逸らせておくとか？","ENG":"...Maybe your duty of distracting me until they jump at me from the behind?","TWN":"……偷襲我前轉移注意力？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"쳇, 눈치 채고 있었나?","JPN":"ちっ、気付いてたのか？","ENG":"Tut, she noticed.","TWN":"嘖，被發現了嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"늦어서 미안해요, 사나에. 다치진 않으셨나요?","JPN":"遅くなってすみません、早苗。怪我はありませんか？","ENG":"Apologies for being late, Sanae. Are you okay?","TWN":"對不起，我們來晚了。早苗，你沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저는 괜찮습니다만……","JPN":"私は大丈夫ですが……","ENG":"I am fine, but...","TWN":"我沒事……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"송구스럽게도 하바키를 붙잡아 두진 못했습니다.","JPN":"申し訳ございません、覇吐を止めおくことはできませんでした。","ENG":"With much regret, I could not stop Habaki from running away.","TWN":"只是很抱歉，沒能抓到幅木。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"흐음~ 또 보네, 원본. 타이밍 좋게 잘 왔어.","JPN":"ふうん～また会ったわね、オリジナル。ちょうどいいところに来てくれたわ。","ENG":"Hmm. So we meet again, Original. You came at a good time.","TWN":"嗯哼～又見面了，正本。你來得正是時候。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당신인가요? 하바키와 협력하는 자가.","JPN":"あなたですか？　覇吐と協力している者は。","ENG":"So it was you who was helping Habaki.","TWN":"就是你嗎？在背後幫助幅木的人？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうよ。","ENG":"Yup.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"나야 그 늙다리가 어떻게 되든 알 바 아니지만, 아버지의 명령이니까.","JPN":"私はあの老いぼれがどうなろうとどうでもいいけど、お父様の命令だからね。","ENG":"I couldn’t care less about that old geezer, but it’s a father’s order.","TWN":"那老傢伙的事我才沒興趣，但這是父親的命令。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하바키가 저지르는 짓은 현실에 크나큰 재앙을 불러올 것입니다.","JPN":"覇吐のしていることは現実に大きな災いを招くはずです。","ENG":"What Habaki is doing will bring colossal damage to this world.","TWN":"幅木做的事會為現實世界帶來極大的災難，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당신들은 잘못된 선택을 하고 있어요.","JPN":"あなたたちは間違った選択をしているのです。","ENG":"You are making the wrong decision.","TWN":"你們這是在助紂為虐。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"야, 꼬맹이.","JPN":"ねえ、ちびちゃん。","ENG":"Hey, kid.","TWN":"喂，小鬼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 꼬맹……?","JPN":"はい？　ちび……？","ENG":"Ah? Kid...?","TWN":"什麼？小鬼……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그거 알아? 그 늙다리는 지금 널 가지고 싶어서 안달이거든.","JPN":"知ってる？　あの老いぼれったらお前を手に入れたくて仕方ないのよ。","ENG":"You should know that the old man reeaaally wants you.","TWN":"你知道嗎？那老傢伙現在一心一意想抓你呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"널 잡아서 데려가면 엄청 좋아할 걸?","JPN":"お前を捕まえて連れて行けばそれはそれは喜ぶだろうね。","ENG":"He’ll be thrilled if I bring you over to him.","TWN":"我把你送給他，他應該會很開心吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당신……!","JPN":"あなた……！","ENG":"You...!","TWN":"你……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"조심해라, 당주. 예삿놈이 아니다.","JPN":"気をつけろ、チビ当主。ただ者ではない。","ENG":"Be careful, Lady. She’s dangerous.","TWN":"堂主小心，她可不是泛泛之輩！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"뒤로 물러서십시오, 당주님.","JPN":"お下がりください、ご当主様。","ENG":"Please step back, my lady.","TWN":"堂主，請退下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"푸훕!","JPN":"ぷっ！","ENG":"Pfft!","TWN":"噗哈！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"긴장 풀어. 누가 납치라도 하겠대?","JPN":"落ち着きなよ。拉致するとかそんなことは一言も言ってないでしょ？","ENG":"Chill. It’s not like I’m going to abduct you.","TWN":"別緊張，我又沒說要綁架她？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"널 여기서 죽였으면 죽였지, 그 음흉한 늙은이가 좋아하는 꼴은 나도 보기 싫거든.","JPN":"ここでお前を殺すならともかく、あの陰険な老いぼれが喜ぶ姿なんて私も見たくないわ。","ENG":"I would have killed you instead. I’d hate to see that old sack of bones smile in the creepiest way possible.","TWN":"要也是在這裡殺掉你，反正我也不想讓那老傢伙稱心如意。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그러니 이번 한 번은 놓아줄게.","JPN":"だから、今回だけは見逃してあげる。","ENG":"So this time, I’ll do you a favor and let you go.","TWN":"不過這次就放你一馬。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……착각하지 마시죠. 저희도 당신을 이대로 보내 드릴 생각은 없습니다.","JPN":"……勘違いしないでください。私たちもこのままあなたを見逃すつもりはありません。","ENG":"...You seem to be mistaken about something. We have no intention of letting you go.","TWN":"……並不是你說了算，我們可不打算就這樣放你走。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"좋아. 그럼 한 번 시험해볼까?","JPN":"いいわよ。じゃあ、一度試してみる？","ENG":"Okay. Let’s test that out, shall we?","TWN":"好啊，那要來試試看嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"원본인 네가, 내 예정된 계획을 어떻게 막아낼지.","JPN":"オリジナルであるお前が、予定された計画をどうやってくい止めるのか。","ENG":"We’ll see how you, the Original, stop me from executing my plans.","TWN":"看你這個正本要如何抵擋我預定好的計畫。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"なんですって？","ENG":"Excuse me?","TWN":"什麼意思？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어이, 터뜨려.","JPN":"爆発させて。","ENG":"Blow ‘em up, fellas!","TWN":"喂，引爆！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이런, 건물이 무너집니다! 조심하십시오!","JPN":"しまった、建物が崩れます！　お気を付けください！","ENG":"The building is falling down! Brace yourselves!","TWN":"糟糕，建築物倒塌中！請小心！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"켁 켁…… 망할 연기. 뭐가 보이질 않는구만.","JPN":"ゲホゲホ……煙のせいで何も見えぬ。","ENG":"*Cough* *Cough* ...The damn smoke. I can’t see anything.","TWN":"咳咳……煙好嗆，什麼都看不到。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님! 무사하십니까? 당주님!","JPN":"ご当主様！　ご無事ですか？　ご当主様！","ENG":"My lady! Are you all right? My lady?!","TWN":"堂主！您沒事吧？堂主！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네, 저는 무사해요.","JPN":"……はい、私は無事です。","ENG":"...Yes, I am fine.","TWN":"……嗯，我沒事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 그 자는 결국 도망친 것 같네요.","JPN":"ですが、あの者は結局逃げたようですね。","ENG":"But it looks like she ran away as well.","TWN":"不過還是被她逃掉了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};